select.foreach:
select '${tableName}' as tableName, date_format(monitor_time, '%H:%i') as monitorTime, data_info as dataInfo
from ${tableName}
where data_type = #{dataType} and monitor_time between #{startTime} and #{endTime}
order by monitor_time desc
limit #{limit}

mapper.select:
select
    out_id as outId, data_type as dataType, data_alarm as dataAlarm, data_info as dataInfoStr , date_format(monitor_time, '%Y-%m-%d %H:%i:%s') as monitorTime
from ${tableName}
where data_type = #{dataType} and monitor_time between #{startTime} and #{endTime}
order by monitor_time desc
limit #{limit}

select alarm_type as alarmType, sum(alarm_count) as alarmCount from ( select alarm_type, count(1) as alarm_count from t_data_out_alarm where start_time <= #{endTime} and (end_time is null or end_time >= #{startTime}) and out_put_id in
#{outPutId}
group by alarm_type union all select alarm_type, count(1) as alarm_count from t_data_out_warn where start_time between #{startTime} and #{endTime} and out_put_id in
#{outPutId}
group by alarm_type ) t group by alarm_type order by alarmCount desc

select.foreach:
select '${tableName}' as tableName, date_format(monitor_time, '%Y-%m-%d %H') as monitorTime
from ${tableName}
where data_type = #{dataType} and monitor_time between #{startTime} and #{endTime}

